export async function getWithdrawInstructionAsync<
  TAccountGame extends string,
  TAccountPlayer extends string,
  TAccountSigner extends string,
  TAccountSystemProgram extends string,
  TAccountTokenProgram extends string,
  TAccountMint extends string,
  TAccountGameTokenAccount extends string,
  TAccountRecipientTokenAccount extends string,
  TProgramAddress extends Address = typeof HORMUZ_RUN_PROGRAM_ADDRESS,
>(
  input: WithdrawAsyncInput<
    TAccountGame,
    TAccountPlayer,
    TAccountSigner,
    TAccountSystemProgram,
    TAccountTokenProgram,
    TAccountMint,
    TAccountGameTokenAccount,
    TAccountRecipientTokenAccount
  >,
  config?: { programAddress?: TProgramAddress },
): Promise<
  WithdrawInstruction<
    TProgramAddress,
    TAccountGame,
    TAccountPlayer,
    TAccountSigner,
    TAccountSystemProgram,
    TAccountTokenProgram,
    TAccountMint,
    TAccountGameTokenAccount,
    TAccountRecipientTokenAccount
  >
> {
  // Program address.
  const programAddress = config?.programAddress ?? HORMUZ_RUN_PROGRAM_ADDRESS;

  // Original accounts.
  const originalAccounts = {
    game: { value: input.game ?? null, isWritable: false },
    player: { value: input.player ?? null, isWritable: true },
    signer: { value: input.signer ?? null, isWritable: true },
    systemProgram: { value: input.systemProgram ?? null, isWritable: false },
    tokenProgram: { value: input.tokenProgram ?? null, isWritable: false },
    mint: { value: input.mint ?? null, isWritable: true },
    gameTokenAccount: {
      value: input.gameTokenAccount ?? null,
      isWritable: true,
    },
    recipientTokenAccount: {
      value: input.recipientTokenAccount ?? null,
      isWritable: true,
    },
  };
  const accounts = originalAccounts as Record<
    keyof typeof originalAccounts,
    ResolvedInstructionAccount
  >;

  // Resolve default values.
  if (!accounts.game.value) {
    accounts.game.value = await findGamePda();
  }
  if (!accounts.player.value) {
    accounts.player.value = await findSendShipPlayerPda({
      signer: getAddressFromResolvedInstructionAccount(
        "signer",
        accounts.signer.value,
      ),
    });
  }
  if (!accounts.systemProgram.value) {
    accounts.systemProgram.value =
      "11111111111111111111111111111111" as Address<"11111111111111111111111111111111">;
  }
  if (!accounts.tokenProgram.value) {
    accounts.tokenProgram.value =
      "TokenkegQfeZyiNwAJbNbGKPFXCWuBvf9Ss623VQ5DA" as Address<"TokenkegQfeZyiNwAJbNbGKPFXCWuBvf9Ss623VQ5DA">;
  }

  const getAccountMeta = getAccountMetaFactory(programAddress, "programId");
  return Object.freeze({
    accounts: [
      getAccountMeta("game", accounts.game),
      getAccountMeta("player", accounts.player),
      getAccountMeta("signer", accounts.signer),
      getAccountMeta("systemProgram", accounts.systemProgram),
      getAccountMeta("tokenProgram", accounts.tokenProgram),
      getAccountMeta("mint", accounts.mint),
      getAccountMeta("gameTokenAccount", accounts.gameTokenAccount),
      getAccountMeta("recipientTokenAccount", accounts.recipientTokenAccount),
    ],
    data: getWithdrawInstructionDataEncoder().encode({}),
    programAddress,
  } as WithdrawInstruction<
    TProgramAddress,
    TAccountGame,
    TAccountPlayer,
    TAccountSigner,
    TAccountSystemProgram,
    TAccountTokenProgram,
    TAccountMint,
    TAccountGameTokenAccount,
    TAccountRecipientTokenAccount
  >);
}

